class OAuthClient {
    constructor(clientId, clientSecret, tokenUrl, redirectUri) {
        this.clientId = clientId;
        this.clientSecret = clientSecret;
        this.tokenUrl = tokenUrl;
        this.redirectUri = redirectUri;
        this.accessToken = null;
        this.refreshToken = null;
        this.expiryTime = 0;

        this.loadTokens();
    }

    async authenticate() {
        const authUrl = `${this.tokenUrl}?response_type=code&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}`;
        window.location.href = authUrl;
    }

    handleCallback() {
        const urlParams = new URLSearchParams(window.location.search);
        const code = urlParams.get('code');
        if (code) {
            this.fetchTokens(code);
        }
    }

    async fetchTokens(code) {
        try {
            const response = await fetch(this.tokenUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded'
                },
                body: new URLSearchParams({
                    grant_type: 'authorization_code',
                    code: code,
                    redirect_uri: this.redirectUri,
                    client_id: this.clientId,
                    client_secret: this.clientSecret
                })
            });

            const data = await response.json();
            if (response.ok) {
                this.accessToken = data.access_token;
                this.refreshToken = data.refresh_token;
                this.expiryTime = Date.now() + (data.expires_in * 1000);
                this.saveTokens();
            } else {
                console.error('Failed to fetch tokens:', data.error_description || 'Unknown error');
            }
        } catch (error) {
            console.error('Error fetching tokens:', error);
        }
    }

    async refreshToken() {
        try {
            const response = await fetch(this.tokenUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded'
                },
                body: new URLSearchParams({
                    grant_type: 'refresh_token',
                    refresh_token: this.refreshToken,
                    client_id: this.clientId,
                    client_secret: this.clientSecret
                })
            });

            const data = await response.json();
            if (response.ok) {
                this.accessToken = data.access_token;
                this.expiryTime = Date.now() + (data.expires_in * 1000);
                this.saveTokens();
            } else {
                console.error('Failed to refresh token:', data.error_description || 'Unknown error');
            }
        } catch (error) {
            console.error('Error refreshing token:', error);
        }
    }

    saveTokens() {
        localStorage.setItem('accessToken', this.accessToken);
        localStorage.setItem('refreshToken', this.refreshToken);
        localStorage.setItem('expiryTime', this.expiryTime);
    }

    loadTokens() {
        this.accessToken = localStorage.getItem('accessToken');
        this.refreshToken = localStorage.getItem('refreshToken');
        const expiry = parseInt(localStorage.getItem('expiryTime'));
        if (!isNaN(expiry)) {
            this.expiryTime = expiry;
        }
    }

    isAccessTokenValid() {
        return Date.now() < this.expiryTime - 5000; // Allow a buffer of 5 seconds
    }

    async getAccessToken() {
        if (!this.isAccessTokenValid()) {
            await this.refreshToken();
        }
        return this.accessToken;
    }
}

